package com.example.sociallogin.network

import retrofit2.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.Body
import retrofit2.http.POST

data class SocialLoginRequest(
    val provider: String,       // "facebook" or "google"
    val authCode: String,       // authorization code (NOT token)
    val redirectUri: String? = null
)

data class AuthResponse(
    val accessToken: String,
    val refreshToken: String,
    val userId: String,
    val displayName: String,
    val email: String?
)

data class ErrorResponse(
    val error: String,
    val message: String
)

interface AuthApiService {
    @POST("auth/social-login")
    suspend fun socialLogin(@Body request: SocialLoginRequest): Response<AuthResponse>
}

object ApiClient {
    // Point this to your backend server which holds the secrets securely
    private const val BASE_URL = "https://api.yourapp.com/v1/"

    val authService: AuthApiService by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(AuthApiService::class.java)
    }
}

