package com.example.sociallogin

import android.content.Context
import android.content.Intent
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import androidx.activity.result.contract.ActivityResultContracts
import com.example.sociallogin.network.ApiClient
import com.example.sociallogin.network.AuthResponse
import com.example.sociallogin.network.SocialLoginRequest
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

sealed class SocialLoginResult {
    data class Success(val authResponse: AuthResponse) : SocialLoginResult()
    data class Error(val message: String, val exception: Throwable? = null) : SocialLoginResult()
    object Cancelled : SocialLoginResult()
}

enum class SocialProvider {
    FACEBOOK,
    GOOGLE
}

class SocialLoginManager(private val activity: ComponentActivity) {

    companion object {
        private const val TAG = "SocialLoginManager"

        // Google OAuth CLIENT ID (public identifier - NOT the secret)
        // The secret stays on your backend server
        private const val GOOGLE_CLIENT_ID = "1234-abcdef.apps.googleusercontent.com"
    }

    private var loginCallback: ((SocialLoginResult) -> Unit)? = null

    // --- Facebook ---
    private val facebookCallbackManager: CallbackManager = CallbackManager.Factory.create()
    private val facebookLoginManager: LoginManager = LoginManager.getInstance()

    // --- Google One Tap ---
    private val oneTapClient: SignInClient = Identity.getSignInClient(activity)
    private val googleSignInRequest: BeginSignInRequest = BeginSignInRequest.builder()
        .setGoogleIdTokenRequestOptions(
            BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                .setSupported(true)
                .setServerClientId(GOOGLE_CLIENT_ID) // Public client ID is safe here
                .setFilterByAuthorizedAccounts(false)
                .build()
        )
        .setAutoSelectEnabled(false)
        .build()

    private lateinit var googleSignInLauncher: ActivityResultLauncher<IntentSenderRequest>

    init {
        registerGoogleSignInLauncher()
        registerFacebookCallback()
    }

    // =====================================================
    // Google Sign-In
    // =====================================================

    private fun registerGoogleSignInLauncher() {
        googleSignInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            if (result.resultCode == ComponentActivity.RESULT_OK) {
                try {
                    val credential = oneTapClient.getSignInCredentialFromIntent(result.data)
                    val idToken = credential.googleIdToken
                    if (idToken != null) {
                        // Send the ID token to your backend for verification
                        // Your backend uses the CLIENT SECRET to verify with Google
                        handleSocialAuthCode(SocialProvider.GOOGLE, idToken)
                    } else {
                        loginCallback?.invoke(
                            SocialLoginResult.Error("Google sign-in failed: No ID token received")
                        )
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "Google sign-in credential extraction failed", e)
                    loginCallback?.invoke(SocialLoginResult.Error("Google sign-in failed", e))
                }
            } else {
                loginCallback?.invoke(SocialLoginResult.Cancelled)
            }
        }
    }

    fun signInWithGoogle(callback: (SocialLoginResult) -> Unit) {
        loginCallback = callback

        oneTapClient.beginSignIn(googleSignInRequest)
            .addOnSuccessListener(activity) { result ->
                try {
                    val intentSenderRequest = IntentSenderRequest.Builder(
                        result.pendingIntent.intentSender
                    ).build()
                    googleSignInLauncher.launch(intentSenderRequest)
                } catch (e: Exception) {
                    Log.e(TAG, "Google One Tap UI launch failed", e)
                    loginCallback?.invoke(SocialLoginResult.Error("Failed to launch Google sign-in", e))
                }
            }
            .addOnFailureListener(activity) { e ->
                Log.e(TAG, "Google One Tap sign-in failed", e)
                loginCallback?.invoke(SocialLoginResult.Error("Google sign-in unavailable", e))
            }
    }

    // =====================================================
    // Facebook Sign-In
    // =====================================================

    private fun registerFacebookCallback() {
        facebookLoginManager.registerCallback(
            facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    // Send the access token to your backend
                    // Your backend uses the APP SECRET to verify with Facebook
                    val accessToken = result.accessToken.token
                    handleSocialAuthCode(SocialProvider.FACEBOOK, accessToken)
                }

                override fun onCancel() {
                    loginCallback?.invoke(SocialLoginResult.Cancelled)
                }

                override fun onError(error: FacebookException) {
                    Log.e(TAG, "Facebook login error", error)
                    loginCallback?.invoke(
                        SocialLoginResult.Error("Facebook login failed", error)
                    )
                }
            }
        )
    }

    fun signInWithFacebook(callback: (SocialLoginResult) -> Unit) {
        loginCallback = callback
        facebookLoginManager.logInWithReadPermissions(
            activity,
            facebookCallbackManager,
            listOf("email", "public_profile")
        )
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    // =====================================================
    // Backend Communication (secrets are on the server)
    // =====================================================

    private fun handleSocialAuthCode(provider: SocialProvider, authCodeOrToken: String) {
        val providerName = when (provider) {
            SocialProvider.FACEBOOK -> "facebook"
            SocialProvider.GOOGLE -> "google"
        }

        // This sends the auth code/token to YOUR backend server.
        // Your server then exchanges it using the CLIENT SECRET
        // which is stored securely in server environment variables.
        kotlinx.coroutines.MainScope().launch {
            try {
                val response = withContext(Dispatchers.IO) {
                    ApiClient.authService.socialLogin(
                        SocialLoginRequest(
                            provider = providerName,
                            authCode = authCodeOrToken
                        )
                    )
                }

                if (response.isSuccessful && response.body() != null) {
                    val authResponse = response.body()!!
                    // Store tokens securely
                    SecureTokenStorage.saveTokens(
                        activity,
                        authResponse.accessToken,
                        authResponse.refreshToken
                    )
                    loginCallback?.invoke(SocialLoginResult.Success(authResponse))
                } else {
                    loginCallback?.invoke(
                        SocialLoginResult.Error(
                            "Authentication failed: ${response.code()} ${response.message()}"
                        )
                    )
                }
            } catch (e: Exception) {
                Log.e(TAG, "Backend authentication request failed", e)
                loginCallback?.invoke(
                    SocialLoginResult.Error("Network error during authentication", e)
                )
            }
        }
    }

    // =====================================================
    // Sign Out
    // =====================================================

    fun signOut(callback: (Boolean) -> Unit) {
        try {
            // Sign out Facebook
            facebookLoginManager.logOut()

            // Sign out Google
            oneTapClient.signOut()
                .addOnCompleteListener {
                    SecureTokenStorage.clearTokens(activity)
                    callback(true)
                }
        } catch (e: Exception) {
            Log.e(TAG, "Sign out failed", e)
            callback(false)
        }
    }

    private fun kotlinx.coroutines.CoroutineScope.launch(
        block: suspend kotlinx.coroutines.CoroutineScope.() -> Unit
    ) = kotlinx.coroutines.launch(block = block)
}

// --- Secure Token Storage ---

package com.example.sociallogin

import android.content.Context
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

object SecureTokenStorage {
    private const val PREFS_NAME = "secure_auth_prefs"
    private const val KEY_ACCESS_TOKEN = "access_token"
    private const val KEY_REFRESH_TOKEN = "refresh_token"

    private fun getEncryptedPrefs(context: Context) =
        EncryptedSharedPreferences.create(
            context,
            PREFS_NAME,
            MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build(),
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )

    fun saveTokens(context: Context, accessToken: String, refreshToken: String) {
        getEncryptedPrefs(context).edit()
            .putString(KEY_ACCESS_TOKEN, accessToken)
            .putString(KEY_REFRESH_TOKEN, refreshToken)
            .apply()
    }

    fun getAccessToken(context: Context): String? =
        getEncryptedPrefs(context).getString(KEY_ACCESS_TOKEN, null)

    fun getRefreshToken(context: Context): String? =
        getEncryptedPrefs(context).getString(KEY_REFRESH_TOKEN, null)

    fun clearTokens(context: Context) {
        getEncryptedPrefs(context).edit().clear().apply()
    }
}

