package com.example.sociallogin

import android.os.Bundle
import android.widget.Toast
import androidx.activity.ComponentActivity

class LoginActivity : ComponentActivity() {

    private lateinit var socialLoginManager: SocialLoginManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // setContentView(R.layout.activity_login)

        socialLoginManager = SocialLoginManager(this)

        // Wire up your Google button:
        // findViewById<View>(R.id.btn_google_sign_in).setOnClickListener {
        //     signInWithGoogle()
        // }

        // Wire up your Facebook button:
        // findViewById<View>(R.id.btn_facebook_sign_in).setOnClickListener {
        //     signInWithFacebook()
        // }
    }

    private fun signInWithGoogle() {
        socialLoginManager.signInWithGoogle { result ->
            handleLoginResult(result)
        }
    }

    private fun signInWithFacebook() {
        socialLoginManager.signInWithFacebook { result ->
            handleLoginResult(result)
        }
    }

    private fun handleLoginResult(result: SocialLoginResult) {
        when (result) {
            is SocialLoginResult.Success -> {
                Toast.makeText(
                    this,
                    "Welcome, ${result.authResponse.displayName}!",
                    Toast.LENGTH_SHORT
                ).show()
                // Navigate to main screen
            }
            is SocialLoginResult.Error -> {
                Toast.makeText(
                    this,
                    "Login failed: ${result.message}",
                    Toast.LENGTH_LONG
                ).show()
            }
            is SocialLoginResult.Cancelled -> {
                Toast.makeText(this, "Login cancelled", Toast.LENGTH_SHORT).show()
            }
        }
    }
}